using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] entries) =>
        entries.Select(e => new OrderItem { ProductName = e.name, Price = e.price, Quantity = e.qty }).ToList();

    // ── CreateOrder — happy path ──────────────────────────────────────

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectCustomerId()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentTime()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= DateTime.UtcNow);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        var items = CreateItems(("Widget", 25.50m, 3));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(76.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithMultipleItems_SumsAllItemTotals()
    {
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 5m, 4));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(40m, order.Total); // (10*2) + (5*4)
    }

    [TestMethod]
    public void CreateOrder_StoresItemsOnOrder()
    {
        var items = CreateItems(("Widget", 10m, 1), ("Gadget", 20m, 2));

        var order = _service.CreateOrder("cust-1", items);

        Assert.HasCount(2, order.Items);
    }

    // ── CreateOrder — validation ──────────────────────────────────────

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
    }

    // ── GetOrder ──────────────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var retrieved = _service.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // ── GetOrdersByCustomer ──────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithOrders_ReturnsMatchingOrders()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _service.CreateOrder("cust-1", CreateItems(("B", 2m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("C", 3m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_CustomerWithNoOrders_ReturnsEmptyList()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-other");

        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyThatCustomersOrders()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("B", 2m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-2");

        var single = Assert.ContainsSingle(orders);
        Assert.AreEqual("cust-2", single.CustomerId);
    }
}

